      const cacheUrl = new URL(request.url);
      cacheUrl.searchParams.delete('ttl');
      cacheUrl.searchParams.delete('cache_key');
      
      const baseKey = cacheUrl.href;
      const finalCacheKey = customKey ? `${baseKey}__${customKey}` : baseKey;
      
      // Check cache first
